import React, { useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { resolveUnitDisplay, formatRent, safeFloat } from '../../../utils/formatters';

const LeaseExpirySection = ({ leases = [], parties = [], loading }) => {
  const navigate = useNavigate();

  // Build party lookup map from Masters — brand_name or company_name by party id
  const partiesMap = useMemo(() => {
    const map = {};
    parties.forEach(p => { map[p.id] = p; });
    return map;
  }, [parties]);

  const handleLeaseClick = (leaseId) => {
    navigate(`/admin/view-lease/${leaseId}`);
  };

  const getExpiryColor = (days) => {
    if (days <= 30) return { bg: '#fee2e2', text: '#991b1b', status: 'Critical' };
    if (days <= 90) return { bg: '#dbeafe', text: '#1d4ed8', status: 'Secure' };
    return { bg: '#dcfce7', text: '#166534', status: 'Active' };
  };

  const processedLeases = useMemo(() => {
    if (!leases || leases.length === 0) return [];
    const now = new Date();
    return leases
      .filter(lease => {
        const status = (lease.status || '').toLowerCase().trim();
        const isActive = ['active', 'approved', 'executed', 'registered', 'occupied'].includes(status);
        return isActive && !!(lease.lease_end || lease.lease_end_date);
      })
      .map(lease => {
        const expiryDate = new Date(lease.lease_end || lease.lease_end_date);
        const diffDays = Math.ceil((expiryDate - now) / (1000 * 60 * 60 * 24));
        const unitNumber = resolveUnitDisplay(lease);
        // Brand name: from Masters partiesMap first, then fallback to lease.brand_name (backend-fetched)
        const party = partiesMap[lease.party_tenant_id];
        const displayName =
          (party?.brand_name && party.brand_name.trim()) ||
          (party?.company_name && party.company_name.trim()) ||
          (lease.brand_name && lease.brand_name.trim()) ||
          (lease.tenant?.brand_name && lease.tenant.brand_name.trim()) ||
          (lease.tenant?.company_name && lease.tenant.company_name.trim()) ||
          unitNumber ||
          `Lease #${lease.id}`;
        const projectLabel = lease.project_name || '';
        const area = safeFloat(lease.chargeable_area || lease.area_leased || lease.units?.chargeable_area || 0);
        return {
          leaseId: lease.id,
          unitNumber: unitNumber || '-',
          displayName,
          projectLabel,
          area,
          amount: formatRent(safeFloat(lease.monthly_rent || 0)),
          days: diffDays,
        };
      })
      .filter(l => l.days > 0)
      .sort((a, b) => a.days - b.days);
  }, [leases, partiesMap]);

  return (
    <div className="echo-card" style={{ border: 'none' }}>
      <h3 style={{ fontSize: '14px', fontWeight: 600, color: '#0f172a', marginBottom: '2px' }}>Leases nearing expiry</h3>
      <p style={{ fontSize: '12px', color: '#64748b', marginBottom: '16px' }}>Lease expiry status · Sorted by urgency</p>

      {loading ? (
        <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>Loading...</div>
      ) : processedLeases.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>No active leases found</div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '14px', maxHeight: '300px', overflowY: 'auto', paddingRight: '8px' }}>
          {processedLeases.slice(0, 5).map((l, i) => {
            const colorInfo = getExpiryColor(l.days);
            return (
              <div
                key={i}
                onClick={() => handleLeaseClick(l.leaseId)}
                style={{
                  display: 'flex', alignItems: 'center', gap: '12px',
                  cursor: 'pointer', padding: '8px 10px', borderRadius: '8px',
                  transition: 'background-color 0.15s', border: '1px solid transparent'
                }}
                onMouseEnter={(e) => { e.currentTarget.style.backgroundColor = '#f8fafc'; e.currentTarget.style.borderColor = '#e2e8f0'; }}
                onMouseLeave={(e) => { e.currentTarget.style.backgroundColor = 'transparent'; e.currentTarget.style.borderColor = 'transparent'; }}
              >
                {/* Unit number badge */}
                <div style={{
                  minWidth: '68px', background: '#eff6ff', borderRadius: '6px',
                  padding: '4px 6px', textAlign: 'center'
                }}>
                  <span style={{ fontSize: '12px', fontWeight: 700, color: '#1d4ed8' }}>{l.unitNumber}</span>
                </div>

                {/* Name + rent */}
                <div style={{ flex: 1, minWidth: 0 }}>
                  <p style={{ fontSize: '13px', color: '#0f172a', margin: 0, fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{l.displayName}</p>
                  <p style={{ fontSize: '11px', color: '#94a3b8', margin: 0 }}>
                    {l.area > 0 ? `${l.area.toLocaleString('en-IN')} sqft · ` : ''}{l.amount} PM
                  </p>
                </div>

                {/* Days + status badge */}
                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: '4px', flexShrink: 0 }}>
                  <span style={{ fontSize: '13px', fontWeight: 600, color: colorInfo.text }}>{l.days}d</span>
                  <span style={{
                    fontSize: '11px', padding: '2px 8px', borderRadius: '9999px',
                    fontWeight: 500, backgroundColor: colorInfo.bg, color: colorInfo.text
                  }}>{colorInfo.status}</span>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default LeaseExpirySection;
